SELECT S.CONTRATO FROM SERVIDOR S WHERE LOWER(S.AREA_INGRESSO) LIKE LOWER('%sociologia%') AND S.SIGLA_CAMPUS = 'LIN' AND S.SAIU_DO_IFG = FALSE AND S.CONTRATO IN ('EFETIVOS', 'TEMPORARIOS') AND EXISTS (SELECT 1 FROM CALC_HORA_AULA_MEDIA H WHERE H.SIAPE = S.PK_SIAPE AND H.ANO = 2022 AND H.SEMESTRE = 2 AND H.SIGLA_CAMPUS = 'LIN') GROUP BY S.CONTRATO